import { useMemo, useState } from "react";
import SEOHead from "@/components/SEOHead";
import MedicalDisclaimer from "@/components/MedicalDisclaimer";
import AdPlaceholder from "@/components/AdPlaceholder";
import RelatedTools from "@/components/RelatedTools";
import ShareButton from "@/components/ShareButton";
import FAQItem from "@/components/FAQItem";

const FAQS = [
  { q: "How many carbohydrates should you eat per day?", a: "Daily carb needs depend on calories, activity, goals, and diet style. Standard diets often use 45% to 65% of calories from carbs, while low-carb diets use less." },
  { q: "What are net carbs?", a: "Net carbs usually means total carbohydrates minus fiber and sometimes sugar alcohols. It is commonly used in low-carb and keto tracking." },
  { q: "What is the difference between simple and complex carbohydrates?", a: "Simple carbs digest quickly, while complex carbs usually contain more fiber and digest more slowly." },
  { q: "How many carbs should you eat on a low carb diet?", a: "Many low-carb diets use about 50 to 150 grams per day, while keto diets often target much lower levels." },
  { q: "Do carbohydrates make you gain weight?", a: "Carbs do not automatically cause weight gain. Weight gain depends mostly on overall calorie surplus over time." },
];

const inputClass = "w-full px-3 py-2 rounded-xl border border-input bg-background text-foreground text-lg font-bold focus:outline-none focus:ring-2 focus:ring-primary/40 transition-all";
const activityMap: Record<string, number> = { Sedentary: 1.2, Light: 1.375, Moderate: 1.55, Active: 1.725, Athlete: 1.9 };
const carbPct: Record<string, number> = { "Lose weight": 0.35, Maintain: 0.45, "Gain muscle": 0.5, "Low carb": 0.2, Keto: 0.05 };
function bmr(gender: string, age: number, heightCm: number, weightKg: number) { return 10 * weightKg + 6.25 * heightCm - 5 * age + (gender === "Male" ? 5 : -161); }

export default function CarbohydrateCalculator() {
  const [age, setAge] = useState(30);
  const [gender, setGender] = useState("Male");
  const [height, setHeight] = useState(175);
  const [weight, setWeight] = useState(80);
  const [activity, setActivity] = useState("Moderate");
  const [goal, setGoal] = useState("Maintain");
  const result = useMemo(() => {
    const maintenance = bmr(gender, age, height, weight) * activityMap[activity];
    const calories = goal === "Lose weight" ? maintenance - 500 : goal === "Gain muscle" ? maintenance + 300 : maintenance;
    const pct = carbPct[goal] || 0.45;
    return { calories, pct, carbs: calories * pct / 4, netCarbs: calories * pct / 4 - 25 };
  }, [age, gender, height, weight, activity, goal]);
  const rows = [["Standard Diet", "45-65%", "225-325g", "281-406g", "General health"], ["Low Carb", "20-30%", "100-150g", "125-188g", "Weight loss"], ["Very Low Carb", "10-20%", "50-100g", "63-125g", "Low carb goals"], ["Ketogenic", "5-10%", "25-50g", "31-63g", "Keto"], ["Athletic Performance", "50-65%", "250-325g", "313-406g", "Training fuel"]];
  return (
    <>
      <SEOHead title="Free Carbohydrate Calculator Online - Calculate Daily Carb Intake Instantly | CalcHive" description="Free online carbohydrate calculator. Calculate your recommended daily carbohydrate intake based on your goal, body stats and activity level instantly. 100% free, no signup required." canonical="/carbohydrate-calculator" keywords="free carbohydrate calculator, daily carb intake calculator free online, how many carbs per day calculator free, net carbs calculator free, low carb calculator free online" category="Health Calculators" breadcrumbName="Free Carbohydrate Calculator Online" schemaType="WebApplication" schemaApplicationCategory="CalculatorApplication" faqs={FAQS} />
      <main className="max-w-3xl mx-auto px-4 sm:px-6 py-10"><div className="mb-8"><span className="text-xs font-semibold uppercase tracking-widest text-teal-600 dark:text-teal-400 bg-teal-50 dark:bg-teal-950/50 px-3 py-1 rounded-full mb-4 inline-block">Health</span><h1 className="text-3xl sm:text-4xl font-extrabold text-foreground tracking-tight mb-3">Free Carbohydrate Calculator Online</h1><p className="text-muted-foreground leading-relaxed">Calculate recommended daily carbs and estimated net carbs from your goal and activity.</p></div><AdPlaceholder size="banner" className="mb-8" />
        <section className="bg-card border border-border rounded-2xl p-6 sm:p-8 shadow-md mb-8"><div className="grid grid-cols-1 sm:grid-cols-2 gap-4 mb-8"><div><label className="text-sm font-semibold block mb-2">Age</label><input type="number" value={age} onChange={(e) => setAge(Number(e.target.value))} className={inputClass} /></div><div><label className="text-sm font-semibold block mb-2">Gender</label><select value={gender} onChange={(e) => setGender(e.target.value)} className={inputClass}><option>Male</option><option>Female</option></select></div><div><label className="text-sm font-semibold block mb-2">Height (cm)</label><input type="number" value={height} onChange={(e) => setHeight(Number(e.target.value))} className={inputClass} /></div><div><label className="text-sm font-semibold block mb-2">Weight (kg)</label><input type="number" value={weight} onChange={(e) => setWeight(Number(e.target.value))} className={inputClass} /></div><div><label className="text-sm font-semibold block mb-2">Activity level</label><select value={activity} onChange={(e) => setActivity(e.target.value)} className={inputClass}>{Object.keys(activityMap).map((x) => <option key={x}>{x}</option>)}</select></div><div><label className="text-sm font-semibold block mb-2">Goal</label><select value={goal} onChange={(e) => setGoal(e.target.value)} className={inputClass}>{Object.keys(carbPct).map((x) => <option key={x}>{x}</option>)}</select></div></div><div className="bg-gradient-to-br from-teal-500 to-teal-700 rounded-2xl p-6 text-center shadow-lg"><p className="text-xs font-semibold uppercase tracking-widest text-white/70 mb-1">Daily Carbohydrates</p><p className="text-5xl sm:text-6xl font-black text-white">{Math.round(result.carbs)}g</p></div><div className="grid grid-cols-1 sm:grid-cols-3 gap-3 mt-4"><div className="bg-accent/60 border border-border rounded-xl p-4 text-center"><p className="text-xs text-muted-foreground">Calories</p><p className="text-lg font-extrabold">{Math.round(result.calories)}</p></div><div className="bg-accent/60 border border-border rounded-xl p-4 text-center"><p className="text-xs text-muted-foreground">Carb %</p><p className="text-lg font-extrabold">{Math.round(result.pct * 100)}%</p></div><div className="bg-accent/60 border border-border rounded-xl p-4 text-center"><p className="text-xs text-muted-foreground">Estimated net carbs</p><p className="text-lg font-extrabold">{Math.max(0, Math.round(result.netCarbs))}g</p></div></div></section><MedicalDisclaimer /><ShareButton />
        <section className="mb-8 space-y-6"><h2 className="text-2xl font-bold">How to Calculate Your Daily Carbohydrate Intake for Free</h2><p className="text-muted-foreground leading-relaxed">Estimate total calories, choose a carb percentage based on your goal, then divide carb calories by four to convert calories into grams.</p><h2 className="text-2xl font-bold">How Many Carbs Should You Eat Per Day</h2><div className="overflow-x-auto"><table className="w-full text-sm border border-border rounded-xl overflow-hidden"><caption className="caption-top text-left font-bold mb-3">Daily Carbohydrate Intake by Diet Type and Goal</caption><thead className="bg-muted/60"><tr>{["Diet Type", "Carb % of Calories", "Daily Carbs on 2000 cal", "Daily Carbs on 2500 cal", "Best For"].map((h) => <th key={h} className="text-left py-3 px-3">{h}</th>)}</tr></thead><tbody className="divide-y divide-border">{rows.map((r) => <tr key={r[0]}>{r.map((c) => <td key={c} className="py-2.5 px-3">{c}</td>)}</tr>)}</tbody></table></div><h2 className="text-2xl font-bold">Free Daily Carb Intake Calculator for Every Diet Goal</h2></section>
        <section className="mb-8"><h3 className="text-xl font-bold mb-4">Frequently Asked Questions</h3><div className="space-y-3">{FAQS.map((faq) => <FAQItem key={faq.q} q={faq.q} a={faq.a} />)}</div></section><AdPlaceholder size="rectangle" className="mx-auto mb-8" /><RelatedTools exclude="/carbohydrate-calculator" headingLevel="h3" /></main>
    </>
  );
}


